package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetPriceInMicros() throws Exception {
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Use the class directly instead of reflection to avoid ClassNotFoundException
    Constructor<LineItem> constructor = LineItem.class.getConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    long result = lineItem.getPriceInMicros();

    assertEquals(priceInMicros, result);
  }
}
